INSERT INTO public.entries (entry_type, subject, teacher, date, summary, attachment_url) VALUES ('Announcement', 'June Fees Reminder Grades Nur To X', 'School Admin', '2026-06-11', 'JUNE FEES REMINDER GRADES NUR TO X Dear Parents , A Gentle Reminder !! This is to inform you all that if any parent wants to replace the June Month Fee PDC, or do NEFT/ GPay against the June PDC, or do Stop payment and pay via other mode, then it should be done on or before 27th May 2026 . No request will be entertained after 27th May 2026. June PDCs will be deposited on 28th May 2026 by us in the bank to be credited on 1st June 2026 . After that bounce charges , if any, will be applicable to th', NULL);
